import React, { useState, useEffect } from 'react';
import { Link, useSearchParams } from 'react-router-dom';
import { motion } from 'framer-motion';
import { ShoppingBag, Search, Star, ShoppingCart, Filter } from 'lucide-react';
import API from '../utils/api';
import { useCart } from '../context/CartContext';
import toast from 'react-hot-toast';

const CATEGORIES = ['all', 'protein', 'creatine', 'pre-workout', 'vitamins', 'weight-gainer', 'fat-burner', 'bcaa', 'accessories', 'apparel'];

export default function StorePage() {
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [searchParams] = useSearchParams();
  const [category, setCategory] = useState(searchParams.get('category') || 'all');
  const { addToCart, count } = useCart();

  useEffect(() => {
    setLoading(true);
    const params = category !== 'all' ? `?category=${category}` : '';
    API.get(`/store${params}`)
      .then(res => setProducts(res.data))
      .catch(() => setProducts([]))
      .finally(() => setLoading(false));
  }, [category]);

  const filtered = products.filter(p =>
    p.name.toLowerCase().includes(search.toLowerCase()) ||
    p.brand?.toLowerCase().includes(search.toLowerCase())
  );

  const handleAddToCart = (product) => {
    addToCart(product, 1);
    toast.success(`${product.name} added to cart!`);
  };

  return (
    <div className="min-h-screen bg-[#0a0a0f] pt-20">
      {/* Header */}
      <div className="relative bg-gradient-to-br from-blue-900/20 to-transparent border-b border-white/10 py-16">
        <div className="max-w-7xl mx-auto px-6 text-center">
          <ShoppingBag size={40} className="text-blue-400 mx-auto mb-4" />
          <h1 className="gym-font text-6xl text-white mb-3">SUPPLEMENT <span className="gradient-text">STORE</span></h1>
          <p className="text-gray-400 text-lg">Premium quality supplements for maximum performance</p>
        </div>
      </div>

      <div className="max-w-7xl mx-auto px-6 py-10">
        {/* Search + filter bar */}
        <div className="flex flex-col md:flex-row gap-4 mb-8">
          <div className="relative flex-1">
            <Search size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" />
            <input className="input-dark pl-10" placeholder="Search products, brands..." value={search} onChange={e => setSearch(e.target.value)} />
          </div>
          <Link to="/cart" className="flex items-center gap-2 bg-orange-500 text-white px-5 py-3 rounded-lg font-semibold hover:bg-orange-600 transition-all">
            <ShoppingCart size={18} /> Cart ({count})
          </Link>
        </div>

        {/* Category tabs */}
        <div className="flex gap-2 flex-wrap mb-10">
          {CATEGORIES.map(cat => (
            <button
              key={cat}
              onClick={() => setCategory(cat)}
              className={`px-4 py-2 rounded-full text-sm font-medium capitalize transition-all ${
                category === cat ? 'bg-orange-500 text-white' : 'bg-white/5 text-gray-400 hover:bg-white/10 border border-white/10'
              }`}
            >
              {cat.replace('-', ' ')}
            </button>
          ))}
        </div>

        {loading ? (
          <div className="flex justify-center py-20">
            <div className="w-10 h-10 border-2 border-orange-500 border-t-transparent rounded-full animate-spin" />
          </div>
        ) : filtered.length === 0 ? (
          <div className="text-center py-20 text-gray-500">No products found</div>
        ) : (
          <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-5">
            {filtered.map((p, i) => (
              <motion.div key={p._id} initial={{ opacity: 0, y: 30 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: i * 0.05 }}>
                <div className="glass rounded-xl overflow-hidden group hover:border-orange-500/30 transition-all flex flex-col">
                  <Link to={`/store/${p._id}`} className="block">
                    <div className="relative h-52 bg-gray-900 overflow-hidden">
                      {p.images?.[0] ? (
                        <img src={p.images[0]} alt={p.name} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-300" />
                      ) : (
                        <div className="w-full h-full flex items-center justify-center">
                          <ShoppingBag size={48} className="text-gray-700" />
                        </div>
                      )}
                      {p.discountPrice && (
                        <div className="absolute top-2 left-2 bg-red-500 text-white text-xs px-2 py-0.5 rounded-full font-bold">
                          {Math.round(((p.price - p.discountPrice) / p.price) * 100)}% OFF
                        </div>
                      )}
                    </div>
                    <div className="p-3">
                      {p.brand && <div className="text-orange-400 text-xs mb-1">{p.brand}</div>}
                      <h3 className="text-white font-semibold text-sm line-clamp-2 mb-2">{p.name}</h3>
                      {p.rating > 0 && (
                        <div className="flex items-center gap-1 text-xs text-yellow-400 mb-2">
                          <Star size={12} fill="currentColor" /> {p.rating.toFixed(1)} ({p.reviewCount})
                        </div>
                      )}
                      <div className="flex items-center gap-2">
                        <span className="text-white font-bold">₹{p.discountPrice || p.price}</span>
                        {p.discountPrice && <span className="text-gray-500 line-through text-xs">₹{p.price}</span>}
                      </div>
                    </div>
                  </Link>
                  <div className="px-3 pb-3 mt-auto">
                    {p.stock > 0 ? (
                      <button
                        onClick={() => handleAddToCart(p)}
                        className="w-full btn-fire text-sm py-2 flex items-center justify-center gap-2"
                      >
                        <ShoppingCart size={15} /> Add to Cart
                      </button>
                    ) : (
                      <div className="w-full text-center text-red-400 text-sm py-2 border border-red-500/20 rounded-lg">Out of Stock</div>
                    )}
                  </div>
                </div>
              </motion.div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
